SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_kep_t_monthly_receive ON sc_kep_t_monthly_receive CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_kep_t_monthly_receive() RETURNS trigger AS $BODY$
BEGIN
--return ;
  if coalesce(NEW.receipt_status::text, '') = '' then NEW.receipt_status :='0';end if;
  if coalesce(NEW.kep_method::text, '') = '' then NEW.kep_method :='SAL';end if;
  if coalesce(NEW.total_keep_notinput::text, '') = '' then NEW.total_keep_notinput :=0;end if;
  if coalesce(NEW.return_money_status::text, '') = '' then NEW.return_money_status :='0';end if;
  if coalesce(NEW.kep_method_transfer::text, '') = '' then NEW.kep_method_transfer :='0';end if;
  if coalesce(NEW.money_return_total::text, '') = '' then NEW.money_return_total :=0;end if;
  if coalesce(NEW.kep_method_amount::text, '') = '' then NEW.kep_method_amount :=0;end if;
  if coalesce(NEW.return_auto::text, '') = '' then NEW.return_auto :='0';end if;
  if coalesce(NEW.return_transfer::text, '') = '' then NEW.return_transfer :='0';end if;
  if coalesce(NEW.salary_time::text, '') = '' then NEW.salary_time :=1;end if;
  if coalesce(NEW.agent_active::text, '') = '' then NEW.agent_active :='0';end if;
  if coalesce(NEW.posted_run::text, '') = '' then NEW.posted_run :=0;end if;
  if coalesce(NEW.salary_file::text, '') = '' then NEW.salary_file :=0;end if;
  if coalesce(NEW.kep_monthly_amount::text, '') = '' then NEW.kep_monthly_amount :=0;end if;
  if coalesce(NEW.amount_form_file::text, '') = '' then NEW.amount_form_file :=0;end if;
  --Niorn 2022-03-28 Amnat ไม่มียอดจากไฟล์ kep_method_transfer ให้เป็น '0'
  if NEW.amount_form_file = 0  then NEW.kep_method_transfer :='0';end if;

  if coalesce(NEW.amount_form_dep::text, '') = '' then NEW.amount_form_dep :=0;end if;
  if coalesce(NEW.ppm_status::text, '') = '' then NEW.ppm_status :='0';end if;

  --คืนใบเสร็จ จากการผ่านรายการ receipt_effectdate =  receipt_date
  if NEW.receipt_status ='2' and coalesce(NEW.receipt_effectdate::text, '') = '' then 
      --ผ่านรายการก่อนวันจริง ต้องแยกวันที่คืนออก เพราะวันจริง จะมีการคืนใบเสร็จเอง เดี๋ยวรายงานจะปนกัน
      --:new.receipt_effectdate :=:new.receipt_date;
      NEW.receipt_effectdate :=  pka.to_date( to_char( statement_timestamp() , 'dd/mm/yyyy' ) );
  end if;
  --ปลด การคืนใบเสร็จเอง ไม่มีการกำหนด ppm_date มา ให้  ppm_date = receipt_date
  if NEW.ppm_status ='1' and coalesce(NEW.ppm_date::text, '') = '' then
      NEW.ppm_date := statement_timestamp();
  end if;

  --ปลด การคืนใบเสร็จเอง เก็บชื่อคนปลด
  if  OLD.ppm_status = '0' and NEW.ppm_status ='1' then
      NEW.ppm_id := current_setting('app.login_id', true);
  end if;


--  if :old.posted_run = '0' and :new.posted_run = '1'   then
--    select total_loan_int  into :new.total_interest_value
--    from sc_mem_m_membership_registered
--    where membership_no = :new.membership_no ; 
--  end if ;
--Niorn 2023-03-21 AMN ดอกเบี้ยสัญญาใหม่ มากกว่า เงินรอจ่ายคืน ต้องไม่คืนใบเสร็จ
if  NEW.receipt_status = '2' and NEW.kep_method_amount >= NEW.kep_amount
    and NEW.kep_amount > 0 then

	NEW.receipt_status := '0';
end if;

  --Niorn 2023-07-19 TGE ผ่านรายการบันทึกวันที่ เอาไว้ออกรายงาน (กรณีผ่านรายการล่วงหน้า )
  if OLD.posted_run = '0' and NEW.posted_run = '1'   then
    NEW.posted_date := to_date(statement_timestamp(),'dd/mm/yyyy');
  end if;

  -- Ming 2026-02-27 TNMA ผ่านรายการแล้ว คนที่มีคืนใบเสร็จ ให้ update หมายเหตุการคืนใบเสร็จ
  IF NEW.receipt_status ='2' and coalesce(NEW.reason_return::text, '') = ''   
        THEN NEW.reason_return := '00';
  END IF;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_kep_t_monthly_receive() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_kep_t_monthly_receive
	BEFORE INSERT OR UPDATE ON sc_kep_t_monthly_receive FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_kep_t_monthly_receive();

